import React, { useState } from 'react';
import InventoryItem from '../components/InventoryItem';

const RoomDetail = ({ room, user, onSave }) => {
    const [items, setItems] = useState(room.inventory);
    const [note, setNote] = useState(room.notes || '');
    const [cleaningDate, setCleaningDate] = useState(room.lastDeepCleaning || '');

    return (
        <div className="page-content fade-in">
            <div style={{display: 'flex', justifyContent: 'space-between', alignItems: 'center'}}>
                <h1>№ {room.id}</h1>
                <div style={{textAlign: 'right'}}>
                    <span style={{fontSize: '10px', color: '#999'}}>ПОСЛЕДНЯЯ ЧИСТКА:</span>
                    <input
                        type="date"
                        value={cleaningDate}
                        onChange={(e) => setCleaningDate(e.target.value)}
                        className="date-input-small"
                    />
                </div>
            </div>

            <div className="product-list">
                {items.map((item, idx) => (
                    <InventoryItem
                        key={idx}
                        item={item}
                        onUpdate={(name, delta) => {
                            setItems(items.map(i => i.name === name ? {...i, count: Math.max(0, i.count + delta)} : i));
                        }}
                    />
                ))}
            </div>

            <textarea
                className="note-area"
                placeholder="Заметки к номеру..."
                value={note}
                onChange={(e) => setNote(e.target.value)}
            />

            <div className="action-block" style={{display: 'flex', gap: '10px', marginTop: '20px'}}>
                <button
                    className="btn-check"
                    onClick={() => onSave({...room, inventory: items, notes: note, lastDeepCleaning: cleaningDate, status: 'checked'})}
                >
                    ЗЕЛЕНАЯ (ОК)
                </button>
                <button
                    className="btn-dnd"
                    onClick={() => onSave({...room, status: 'dnd'})}
                >
                    КРАСНАЯ (DND)
                </button>
            </div>
        </div>
    );
};

export default RoomDetail;
